define(['core/notification'],function(Notification){var PDFJS_URL=M.cfg.wwwroot+'/mod/videoplayer/thirdpartylibs/pdfjs/pdf.min.mjs';var PDFJS_WORKER_URL=M.cfg.wwwroot+'/mod/videoplayer/thirdpartylibs/pdfjs/pdf.worker.min.mjs';var pdfjsPromise=null;var loadPdfJs=function(){if(!pdfjsPromise){pdfjsPromise=import(PDFJS_URL).then(function(pdfjsLib){pdfjsLib.GlobalWorkerOptions.workerSrc=PDFJS_WORKER_URL;return pdfjsLib;});}return pdfjsPromise;};var hide=function(node,value){if(node){node.hidden=value;}};var isFullscreen=function(root){return document.fullscreenElement||root.classList.contains('is-fallback-fullscreen');};var showError=function(root,error){hide(root.querySelector('.mod-videoplayer-pdfjs-canvas-wrap'),true);hide(root.querySelector('.mod-videoplayer-pdfjs-topbar'),true);hide(root.querySelector('[data-region="pdfjs-loading"]'),true);hide(root.querySelector('[data-region="pdfjs-error"]'),false);if(error&&window.console){window.console.error(error);}};var block=function(event){event.preventDefault();event.stopPropagation();return false;};var hardenViewer=function(root,canvas){[root,canvas].forEach(function(node){if(!node){return;}node.setAttribute('draggable','false');node.addEventListener('contextmenu',block,true);node.addEventListener('dragstart',block,true);node.addEventListener('copy',block,true);node.addEventListener('cut',block,true);node.addEventListener('paste',block,true);node.addEventListener('selectstart',block,true);});root.addEventListener('keydown',function(event){var key=(event.key||'').toLowerCase();if((event.ctrlKey||event.metaKey)&&['s','p','c','a'].indexOf(key)!==-1){block(event);}},true);};var initViewer=function(root,pdfjsLib){var pdfUrl=root.getAttribute('data-pdf-url');var canvas=root.querySelector('.mod-videoplayer-pdfjs-canvas');var previous=root.querySelector('[data-action="previous-page"]');var next=root.querySelector('[data-action="next-page"]');var fullscreen=root.querySelector('[data-action="fullscreen"]');var currentPageNode=root.querySelector('[data-region="current-page"]');var totalPagesNode=root.querySelector('[data-region="total-pages"]');var loading=root.querySelector('[data-region="pdfjs-loading"]');var wrap=root.querySelector('.mod-videoplayer-pdfjs-canvas-wrap');if(!pdfUrl||!canvas){showError(root);return;}hardenViewer(root,canvas);var context=canvas.getContext('2d');var pdfDocument=null,pageNumber=Math.max(1,parseInt(root.getAttribute('data-initial-page'),10)||1),rendering=false,pendingPage=null,firstRender=true;var updateButtons=function(){if(!pdfDocument){return;}if(previous){previous.disabled=pageNumber<=1;}if(next){next.disabled=pageNumber>=pdfDocument.numPages;}if(currentPageNode){currentPageNode.textContent=String(pageNumber);}if(totalPagesNode){totalPagesNode.textContent=String(pdfDocument.numPages);}};var prefetch=function(num){if(!pdfDocument||num<1||num>pdfDocument.numPages){return;}pdfDocument.getPage(num).catch(function(){});};var getAvailableBox=function(){var rect=wrap?wrap.getBoundingClientRect():{width:900,height:900};var width=Math.max(Math.floor((rect.width||wrap.clientWidth||900)-24),300);var fallbackHeight=isFullscreen(root)?window.innerHeight:Math.min(window.innerHeight*.76,860);var height=Math.max(Math.floor((rect.height||wrap.clientHeight||fallbackHeight)-24),360);return{width:width,height:height};};var renderPage=function(num){rendering=true;canvas.classList.add('is-rendering');if(firstRender){hide(loading,false);}pdfDocument.getPage(num).then(function(page){var box=getAvailableBox();var base=page.getViewport({scale:1});var fitWidth=box.width/base.width;var fitHeight=box.height/base.height;var cssScale=Math.min(fitWidth,fitHeight);if(!isFullscreen(root)){cssScale=Math.min(cssScale,1.9);}var viewport=page.getViewport({scale:cssScale});var outputScale=isFullscreen(root)?Math.min(window.devicePixelRatio||1,3):Math.min(window.devicePixelRatio||1,2.25);canvas.width=Math.floor(viewport.width*outputScale);canvas.height=Math.floor(viewport.height*outputScale);canvas.style.width=Math.floor(viewport.width)+'px';canvas.style.height=Math.floor(viewport.height)+'px';context.setTransform(1,0,0,1,0,0);return page.render({canvasContext:context,viewport:viewport,transform:outputScale!==1?[outputScale,0,0,outputScale,0,0]:null}).promise;}).then(function(){rendering=false;firstRender=false;hide(loading,true);canvas.classList.remove('is-rendering');updateButtons();prefetch(pageNumber+1);prefetch(pageNumber-1);if(pendingPage!==null){var nextPage=pendingPage;pendingPage=null;renderPage(nextPage);}}).catch(function(error){rendering=false;Notification.exception(error);showError(root,error);});};var queue=function(num){if(rendering){pendingPage=num;}else{renderPage(num);}};var go=function(num){if(!pdfDocument){return;}pageNumber=Math.max(1,Math.min(pdfDocument.numPages,num));queue(pageNumber);};if(previous){previous.addEventListener('click',function(event){event.preventDefault();go(pageNumber-1);});}if(next){next.addEventListener('click',function(event){event.preventDefault();go(pageNumber+1);});}if(fullscreen){fullscreen.addEventListener('click',function(){if(document.fullscreenElement){document.exitFullscreen();return;}if(root.classList.contains('is-fallback-fullscreen')){root.classList.remove('is-fallback-fullscreen');document.documentElement.classList.remove('mod-videoplayer-no-scroll');document.body.classList.remove('mod-videoplayer-no-scroll');queue(pageNumber);return;}if(root.requestFullscreen){root.requestFullscreen().catch(function(){root.classList.add('is-fallback-fullscreen');document.documentElement.classList.add('mod-videoplayer-no-scroll');document.body.classList.add('mod-videoplayer-no-scroll');queue(pageNumber);});}else{root.classList.add('is-fallback-fullscreen');document.documentElement.classList.add('mod-videoplayer-no-scroll');document.body.classList.add('mod-videoplayer-no-scroll');queue(pageNumber);}});document.addEventListener('fullscreenchange',function(){if(!document.fullscreenElement){root.classList.remove('is-fallback-fullscreen');document.documentElement.classList.remove('mod-videoplayer-no-scroll');document.body.classList.remove('mod-videoplayer-no-scroll');}if(pdfDocument){queue(pageNumber);}});}var resizeTimer=null;window.addEventListener('resize',function(){if(!pdfDocument){return;}clearTimeout(resizeTimer);resizeTimer=setTimeout(function(){queue(pageNumber);},180);});hide(loading,false);pdfjsLib.getDocument({url:pdfUrl,withCredentials:true,rangeChunkSize:262144}).promise.then(function(pdf){pdfDocument=pdf;pageNumber=Math.max(1,Math.min(pageNumber,pdfDocument.numPages));updateButtons();renderPage(pageNumber);}).catch(function(error){Notification.exception(error);showError(root,error);});};var init=function(){var viewers=Array.prototype.slice.call(document.querySelectorAll('.mod-videoplayer-pdfjs-viewer'));if(!viewers.length){return;}loadPdfJs().then(function(pdfjsLib){viewers.forEach(function(root){initViewer(root,pdfjsLib);});}).catch(function(error){Notification.exception(error);viewers.forEach(function(root){showError(root,error);});});};return{init:init};});
